async (page) => {
  await page.locator('#login-name-input').fill('ClaudeBot3');
  await page.locator('#login-password-input').fill('password123');
  await page.locator('#login').click();
  await page.waitForTimeout(6000);
  await page.keyboard.press('Escape');
  await page.waitForTimeout(1000);
  await page.addScriptTag({ path: '/home/patnir41/projects/kaetram-agent/state_extractor.js' });
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => {
    if (!window.__latestGameState) return '{"error":"no state"}';
    return JSON.stringify({
      pos: window.__latestGameState.player_position,
      hp: window.__latestGameState.player_stats.hp,
      max_hp: window.__latestGameState.player_stats.max_hp,
      chat: window.__latestGameState.ui_state.recent_chat
    });
  });
  return state;
}
